// // This is a 2-to-1 demultiplexer that selects the first input when ctrl=0 and the second input when ctrl=1
module top_module(input [1:0] data, input ctrl, output reg out);always @(*) begin
    case(ctrl)
      1'b0: out = data[0];
      1'b1: out = data[1];
      default: out = 1'b0; // Adding default case for safety
    endcase
  end

endmodule
